// cross-platform packaging, accessibility review, and production behavior require controlled transfer gates.
package main

import "fmt"

type PokedexPolicy struct {
	BaseOrigin        string
	PageLimit         int
	MaximumConcurrent int
	CacheCapacity     int
}

type PokedexEvidence struct {
	Revision     string
	ResourceKey  string
	StateDigest  string
	TraceDigest  string
